SELECT participant_name 
FROM performances 
WHERE rating = (SELECT MAX(rating) FROM performances);

SELECT DISTINCT participant_name
FROM performances
WHERE rating = 9 AND feedback LIKE '%Excellent%';

SELECT *
FROM performances
WHERE music_score_reading_completeness = 1;

SELECT DISTINCT participant_name
FROM performances
WHERE recording_location = 'Studio A';

SELECT participant_name, rating
FROM performances
WHERE rating > (SELECT AVG(rating) FROM performances);
